    // Methodology
    methPageTitle: "Vores metode",
    methPageDesc: "Hvorfor vores taekwondo-specifikke træningslogik skaber bedre atleter end generelle programmer.",
    methHeroTitle: "Hvorfor vores taekwondo-logik er bedre",
    methHeroSubtitle: "De fleste træningsprogrammer er bygget til generel fitness eller klassisk styrketræning. Taekwondo kræver noget andet.",
    methWhyTitle: "Bygget til taekwondo — ikke tilpasset fra fitness",
    methWhyBody: "Vores logik er udviklet med udgangspunkt i de faktiske krav i taekwondo: eksplosivitet, reaktion, mobilitet, gentagne højintense aktioner, kontrol i spark, evnen til at holde kvalitet sent i kampen og balancen mellem tekniktræning og fysisk udvikling. Programmet er derfor ikke bare 'styrke ved siden af taekwondo'. Det er bygget til at understøtte sporten — ikke forstyrre den.",
    methAdaptTitle: "Hvordan programmet tilpasser sig kampbelastning",
    methAdaptBody: "I taekwondo giver det ikke mening at træne ens hver uge. Belastningen ændrer sig alt efter sparring, teknikpas, stævner, vægtstyring og restitution. Derfor tilpasser programmet sig atletens reelle uge:",
    methAdaptList1: "Hvor mange taekwondo-pas der er",
    methAdaptList2: "Hvor hårde pasene er",
    methAdaptList3: "Om der er sparring eller teknisk fokus",
    methAdaptList4: "Hvor tæt man er på kamp eller stævne",
    methAdaptList5: "Om kroppen er presset eller klar til høj belastning",
    methAdaptOutro: "Det betyder, at styrke- og konditionsdelen bliver justeret efter kampbelastningen, så atleten ikke bliver overbelastet eller møder træt op til de vigtigste pas.",
    methSparTitle: "Sparring, restitution og eksplosivitet",
    methSparIntro: "Sparring er i sig selv en belastning. Mange programmer ignorerer det og lægger tung træning oveni, som om atleten ikke allerede bruger kroppen hårdt flere gange om ugen. Det er en klassisk fejl. Vores tilgang tager højde for tre ting samtidig:",
    methSparSparring: "Sparring",
    methSparSparringBody: "Når en uge indeholder hård sparring, bliver den fysiske træning justeret, så den støtter præstationen i stedet for at dræne benene og sænke kvaliteten.",
    methSparRecovery: "Restitution",
    methSparRecoveryBody: "Programmet planlægger ikke kun belastning, men også hvornår kroppen skal absorbere træningen. Det reducerer risikoen for, at atleten hele tiden træner træt, tungt og halvt klar.",
    methSparExplosive: "Eksplosivitet",
    methSparExplosiveBody: "Taekwondo handler ikke bare om at blive stærkere, men om at kunne omsætte styrke til fart, timing og power. Derfor prioriterer programmet eksplosive kvaliteter og bevægelser, der giver værdi i kampen — ikke bare flere kilo på stangen.",
    methErrorTitle: "Reducerer fejlprogrammering for TKD-atleter",
    methErrorIntro: "En af de største udfordringer for taekwondo-atleter er fejlprogrammering. Det sker typisk når man:",
    methErrorList1: "Træner for tungt for tæt på sparring",
    methErrorList2: "Bygger for meget muskeltræthed i benene",
    methErrorList3: "Bruger bodybuilding-logik i stedet for kampidræt",
    methErrorList4: "Overser restitution",
    methErrorList5: "Træner 'hårdt' uden at tænke på timing og samlet ugentlig belastning",
    methErrorOutro: "Vores program reducerer de fejl ved at tage højde for helheden. Det ser ikke fysisk træning som noget isoleret, men som en del af atletens samlede performance. Målet er ikke bare at presse flere øvelser ind. Målet er at vælge den rigtige træning på det rigtige tidspunkt.",
    methResultsTitle: "Hvilke resultater det skaber",
    methResultsIntro: "Når programmet er bygget korrekt til taekwondo, ser man typisk bedre resultater dér, hvor det faktisk betyder noget:",
    methResultsList1: "Mere eksplosivitet i spark og bevægelser",
    methResultsList2: "Bedre kvalitet i sparring over længere tid",
    methResultsList3: "Mindre unødig træthed i ben og hofter",
    methResultsList4: "Bedre balance mellem styrke, fart og mobilitet",
    methResultsList5: "Mere stabil udvikling uden at kroppen konstant føles tung",
    methResultsList6: "Større sandsynlighed for at ramme topniveau op til kamp og stævner",
    methResultsOutro: "Det giver ikke bare en stærkere atlet i fitnesscentret. Det giver en atlet, der er bedre forberedt til at præstere på måtten.",
