    methAdaptOutro: "هذا يعني أن جزء القوة والتكييف يتم تعديله ليناسب حمل القتال، حتى لا يتعرض الرياضي للإرهاق أو يظهر متعبًا في أهم الجلسات.",
    methSparTitle: "السجال، التعافي، والانفجارية",
    methSparIntro: "السجال هو حمل بحد ذاته. تتجاهل العديد من البرامج هذا وتضيف تدريبًا ثقيلًا فوقه، كما لو أن الرياضي لا يدفع جسده بقوة عدة مرات في الأسبوع. هذا خطأ كلاسيكي. نهجنا يأخذ في الاعتبار ثلاثة أشياء في وقت واحد:",
    methSparSparring: "السجال",
    methSparSparringBody: "عندما يتضمن الأسبوع سجالًا صعبًا، يتم تعديل التدريب البدني بحيث يدعم الأداء بدلاً من إرهاق الساقين وتقليل الجودة.",
    methSparRecovery: "التعافي",
    methSparRecoveryBody: "لا يخطط البرنامج للحمل فحسب، بل يخطط أيضًا لمتى يجب أن يمتص الجسم التدريب. هذا يقلل من خطر تدريب الرياضي باستمرار وهو متعب، ثقيل، ونصف جاهز.",
    methSparExplosive: "الانفجارية",
    methSparExplosiveBody: "التايكوندو لا يتعلق فقط بأن تصبح أقوى — بل يتعلق بتحويل القوة إلى سرعة، توقيت، وقوة. لهذا السبب يولي البرنامج الأولوية للصفات الحركية الانفجارية والحركات التي تقدم قيمة في القتال — وليس فقط المزيد من الكيلوغرامات على البار.",
    methErrorTitle: "تقليل أخطاء البرمجة لرياضيي التايكوندو",
    methErrorIntro: "أحد أكبر التحديات التي تواجه رياضيي التايكوندو هو سوء البرمجة. يحدث هذا عادة عندما:",
    methErrorList1: "تتدرب بقوة شديدة بالقرب من السجال",
    methErrorList2: "تبني الكثير من إرهاق الساقين",
    methErrorList3: "تستخدم منطق كمال الأجسام بدلاً من منطق الرياضات القتالية",
    methErrorList4: "تتجاهل التعافي",
    methErrorList5: "تتدرب 'بجد' دون مراعاة التوقيت والحمل الأسبوعي الإجمالي",
    methErrorOutro: "يقلل برنامجنا هذه الأخطاء من خلال النظر إلى الصورة الكاملة. لا يعامل التدريب البدني كشيء معزول — بل كجزء من الأداء الكلي للرياضي.",
    methResultsTitle: "ما هي النتائج التي يخلقها",
    methResultsIntro: "عندما يتم بناء البرنامج بشكل صحيح للتايكوندو، ترى عادة نتائج أفضل حيثما يهم حقًا:",
    methResultsList1: "مزيد من الانفجارية في الركلات والحركات",
    methResultsList2: "جودة أفضل في السجال على فترات أطول",
